<script setup lang="ts">
const props = defineProps({
  modelValue: {
    type: String,
    default: ''
  },
  items: {
    type: Array as () => { text: string, value: string }[],
    default: () => []
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
})

const emit = defineEmits(['update:model-value'])

const variant = {
  primary: 'text-primary-500 bg-primary-50',
  success: 'text-success-500 bg-success-50',
  info: 'text-info-500 bg-info-50',
  warning: 'text-warning-500 bg-warning-50',
  error: 'text-error-500 bg-error-50',
}

const bgColor = computed(() => {
  return variant[props.color]
})

const buttonClasses = (value: string) => {
  const baseClass = 'py-2.5 px-4 transition'
  const color = props.modelValue === value ? bgColor.value : 'hover:bg-gray-100'
  return `${baseClass} ${color}`
}
</script>

<template>
  <div class="grid border divide-x rounded-lg overflow-hidden" :class="`grid-cols-${items.length}`">
    <button v-for="(item, i) in props.items" :class="buttonClasses(item.value)"
            @click="emit('update:model-value', item.value)">
      {{ item.text }}
    </button>
  </div>
</template>

<style scoped></style>